```typescript
// --- Workflow Row Types (private) ---

type WorkflowRow = {
  id: string;
  name: string;
  description: string | null;
  enabled: number;
  definition: string;
  webhookSecret: string | null;
  createdByAgentId: string | null;
  createdAt: string;
  lastUpdatedAt: string;
};

function rowToWorkflow(row: WorkflowRow): Workflow {
  return {
    id: row.id,
    name: row.name,
    description: row.description ?? undefined,
    enabled: row.enabled === 1,
    definition: JSON.parse(row.definition),
    webhookSecret: row.webhookSecret ?? undefined,
    createdByAgentId: row.createdByAgentId ?? undefined,
    createdAt: row.createdAt,
    lastUpdatedAt: row.lastUpdatedAt,
  };
}

type WorkflowRunRow = {
  id: string;
  workflowId: string;
  status: string;
  triggerData: string | null;
  context: string | null;
  error: string | null;
  startedAt: string;
  lastUpdatedAt: string;
  finishedAt: string | null;
};

function rowToWorkflowRun(row: WorkflowRunRow): WorkflowRun {
  return {
    id: row.id,
    workflowId: row.workflowId,
    status: row.status as WorkflowRunStatus,
    triggerData: row.triggerData ? JSON.parse(row.triggerData) : undefined,
    context: row.context ? JSON.parse(row.context) : undefined,
    error: row.error ?? undefined,
    startedAt: row.startedAt,
    lastUpdatedAt: row.lastUpdatedAt,
    finishedAt: row.finishedAt ?? undefined,
  };
}

type WorkflowRunStepRow = {
  id: string;
  runId: string;
  nodeId: string;
  nodeType: string;
  status: string;
  input: string | null;
  output: string | null;
  error: string | null;
  startedAt: string;
  finishedAt: string | null;
};

function rowToWorkflowRunStep(row: WorkflowRunStepRow): WorkflowRunStep {
  return {
    id: row.id,
    runId: row.runId,
    nodeId: row.nodeId,
    nodeType: row.nodeType,
    status: row.status as WorkflowRunStepStatus,
    input: row.input ? JSON.parse(row.input) : undefined,
    output: row.output ? JSON.parse(row.output) : undefined,
    error: row.error ?? undefined,
    startedAt: row.startedAt,
    finishedAt: row.finishedAt ?? undefined,
  };
}

// --- Workflow CRUD ---

export function createWorkflow(data: {
  name: string;
  description?: string;
  definition: WorkflowDefinition;
  createdByAgentId?: string;
}): Workflow {
  const id = crypto.randomUUID();
  const webhookSecret = crypto.randomUUID();
  const row = getDb()
    .prepare<WorkflowRow, [string, string, string | null, string, string, string | null, string]>(
      `INSERT INTO workflows (id, name, description, definition, webhookSecret, createdByAgentId, lastUpdatedAt)
       VALUES (?, ?, ?, ?, ?, ?, datetime('now')) RETURNING *`
    )
    .get(id, data.name, data.description ?? null, JSON.stringify(data.definition), webhookSecret, data.createdByAgentId ?? null, new Date().toISOString());
  if (!row) throw new Error("Failed to create workflow");
  return rowToWorkflow(row);
}

export function getWorkflow(id: string): Workflow | null {
  const row = getDb()
    .prepare<WorkflowRow, [string]>("SELECT * FROM workflows WHERE id = ?")
    .get(id);
  return row ? rowToWorkflow(row) : null;
}

export function getWorkflowByWebhookSecret(secret: string): Workflow | null {
  const row = getDb()
    .prepare<WorkflowRow, [string]>("SELECT * FROM workflows WHERE webhookSecret = ?")
    .get(secret);
  return row ? rowToWorkflow(row) : null;
}

export function listWorkflows(filters?: { enabled?: boolean }): Workflow[] {
  let query = "SELECT * FROM workflows WHERE 1=1";
  const params: (string | number)[] = [];
  if (filters?.enabled !== undefined) {
    query += " AND enabled = ?";
    params.push(filters.enabled ? 1 : 0);
  }
  query += " ORDER BY name ASC";
  return getDb()
    .prepare<WorkflowRow, (string | number)[]>(query)
