## Phase 5: LLM Provider and `llm-classify` Node

### Overview
Add the LLM provider abstraction and the `llm-classify` condition node. This enables intelligent routing ("is this a bug or feature request?") using cheap/fast models via OpenRouter or Claude CLI fallback.

### Changes Required:

#### 5.1 LLM Provider Abstraction

**File**: `src/workflows/llm-provider.ts` (new)
**Changes**: `LlmProvider` interface with OpenRouter (Vercel AI SDK) and Claude CLI fallback

```typescript
import { z } from "zod";
import { zodToJsonSchema } from "zod-to-json-schema";

export interface LlmProvider {
  query<T>(input: string, schema: z.ZodSchema<T>): Promise<T>;
}

class OpenRouterProvider implements LlmProvider {
  async query<T>(input: string, schema: z.ZodSchema<T>): Promise<T> {
    const { generateObject } = await import("ai");
    const { createOpenAI } = await import("@ai-sdk/openai");

    const openrouter = createOpenAI({
      baseURL: "https://openrouter.ai/api/v1",
      apiKey: process.env.OPENROUTER_API_KEY,
    });

    const { object } = await generateObject({
      model: openrouter("google/gemini-2.0-flash-001"),
      schema,
      prompt: input,
    });
    return object;
  }
}

class ClaudeCliProvider implements LlmProvider {
  async query<T>(input: string, schema: z.ZodSchema<T>): Promise<T> {
    const jsonSchema = JSON.stringify(zodToJsonSchema(schema));
    const proc = Bun.spawn(
      ["claude", "-p", "--model", "haiku", "--output-format", "json", "--json-schema", jsonSchema],
      { stdin: "pipe", stdout: "pipe", stderr: "pipe" }
    );
    proc.stdin.write(input);
    proc.stdin.end();
    const output = await new Response(proc.stdout).text();
    await proc.exited;
    const parsed = JSON.parse(output);
    // Claude CLI with --output-format json wraps result, extract the actual content
    const result = parsed.result ?? parsed;
    return schema.parse(result);
  }
}

let provider: LlmProvider | null = null;

export function createProvider(): LlmProvider {
  if (provider) return provider;
  if (process.env.OPENROUTER_API_KEY) {
    provider = new OpenRouterProvider();
  } else {
    provider = new ClaudeCliProvider();
  }
  return provider;
}
```

#### 5.2 LLM Classify Node

**File**: `src/workflows/nodes/llm-classify.ts` (new)
**Changes**: Uses `createProvider().query()` with a Zod enum schema built from categories

```typescript
import { z } from "zod";
import { createProvider } from "../llm-provider";
import { interpolate } from "../template";
import type { NodeResult } from "../engine";

export interface LlmClassifyConfig {
  prompt: string;
  categories: string[];
  model?: string;
  fallbackPort?: string;
}

export async function executeLlmClassify(
  config: LlmClassifyConfig,
  ctx: Record<string, unknown>
): Promise<NodeResult> {
  const prompt = interpolate(config.prompt, ctx);
  const categories = config.categories;
  const schema = z.object({
    category: z.enum(categories as [string, ...string[]]),
    confidence: z.number().min(0).max(1),
  });

  try {
    const provider = createProvider();
    const result = await provider.query(
      `Classify the following into one of these categories: ${categories.join(", ")}.\n\n${prompt}`,
      schema
    );
    return {
      mode: "instant",
      nextPort: result.category,
      output: { category: result.category, confidence: result.confidence },
    };
  } catch (err) {
    const fallback = config.fallbackPort ?? categories[categories.length - 1];
    return {
      mode: "instant",
      nextPort: fallback,
      output: { category: fallback, confidence: 0, error: String(err) },
    };
  }
}
```

