import { createTaskExtended } from "../../be/db";
import { interpolate } from "../template";
import type { NodeResult } from "../engine";

export interface DelegateToAgentConfig {
  agentId: string;
  taskTemplate: string;
  tags?: string[];
  offerMode?: boolean;
}

export function executeDelegateToAgent(
  config: DelegateToAgentConfig,
  ctx: Record<string, unknown>,
  runId: string,
  stepId: string
): NodeResult {
  const taskDescription = interpolate(config.taskTemplate, ctx);
  const tags = (config.tags ?? []).map((t) => interpolate(t, ctx));
  const task = createTaskExtended(taskDescription, {
    agentId: config.offerMode ? null : config.agentId,
    offeredTo: config.offerMode ? config.agentId : undefined,
    source: "workflow",
    tags,
    workflowRunId: runId,
    workflowRunStepId: stepId,
  });
  return {
    mode: "async",
    nextPort: "default",
    output: { taskId: task.id, taskStatus: task.status, agentId: config.agentId },
  };
}
```

#### 6.3 Code Match Node

**File**: `src/workflows/nodes/code-match.ts` (new)
**Changes**: Sandboxed execution via `new Function()` with restricted scope

```typescript
import type { NodeResult } from "../engine";

export interface CodeMatchConfig {
  code: string;
  outputPorts: string[];
}

export function executeCodeMatch(
  config: CodeMatchConfig,
  ctx: Record<string, unknown>
): NodeResult {
  // Build a sandboxed function — no access to require, import, process, Bun, globalThis
  const sandbox = {
    require: undefined,
    import: undefined,
    process: undefined,
    Bun: undefined,
    globalThis: undefined,
    global: undefined,
    fetch: undefined,
    setTimeout: undefined,
    setInterval: undefined,
  };

  const fn = new Function(
    ...Object.keys(sandbox),
    "input",
    `"use strict"; return (${config.code})(input);`
  );

  const result = fn(...Object.values(sandbox), ctx);

  // Map result to port name
  let port: string;
  if (typeof result === "boolean") {
    port = result ? "true" : "false";
  } else if (typeof result === "string") {
    port = result;
  } else {
    port = String(result);
  }

  // Validate port is in the declared outputPorts
  if (!config.outputPorts.includes(port)) {
    throw new Error(
      `code-match returned "${port}" which is not in outputPorts: [${config.outputPorts.join(", ")}]`
    );
  }

  return { mode: "instant", nextPort: port, output: { result: port } };
}
