## Phase 7: Heartbeat Recovery and Observability

### Overview
Add stuck-workflow recovery to the heartbeat sweep. Ensure workflow runs stuck in `waiting` state (where the associated task reached a terminal status but the event was missed) are recovered and resumed.

### Changes Required:

#### 7.1 Recovery Function

**File**: `src/be/db.ts`
**Changes**: Add `getStuckWorkflowRuns()` query function

```typescript
export interface StuckWorkflowRun {
  runId: string;
  stepId: string;
  nodeId: string;
  taskStatus: string;
  taskOutput: string | null;
  workflowId: string;
}

export function getStuckWorkflowRuns(): StuckWorkflowRun[] {
  return getDb()
    .prepare<StuckWorkflowRun, []>(`
      SELECT
        wr.id as runId,
        wrs.id as stepId,
        wrs.nodeId,
        at.status as taskStatus,
        at.output as taskOutput,
        wr.workflowId
      FROM workflow_runs wr
      JOIN workflow_run_steps wrs ON wrs.runId = wr.id AND wrs.status = 'waiting'
      JOIN agent_tasks at ON at.workflowRunStepId = wrs.id
      WHERE wr.status = 'waiting'
        AND at.status IN ('completed', 'failed', 'cancelled')
    `)
    .all();
}
```

#### 7.2 Recovery Logic

**File**: `src/workflows/recovery.ts` (new)
**Changes**: Function that processes stuck workflow runs

```typescript
import {
  getStuckWorkflowRuns,
  getWorkflowRun,
  getWorkflow,
  updateWorkflowRunStep,
  updateWorkflowRun,
} from "../be/db";
import { walkDag, getSuccessors } from "./engine";

export async function recoverStuckWorkflowRuns(): Promise<number> {
  const stuckRuns = getStuckWorkflowRuns();
  let recovered = 0;

  for (const stuck of stuckRuns) {
    try {
      const run = getWorkflowRun(stuck.runId);
      const workflow = getWorkflow(stuck.workflowId);
      if (!run || !workflow) continue;

      if (stuck.taskStatus === "completed") {
        // Resume — same logic as the event bus handler
        updateWorkflowRunStep(stuck.stepId, {
          status: "completed",
          output: { taskOutput: stuck.taskOutput },
          finishedAt: new Date().toISOString(),
        });
        const ctx = (run.context ?? {}) as Record<string, unknown>;
        ctx[stuck.nodeId] = { taskOutput: stuck.taskOutput };
        updateWorkflowRun(stuck.runId, { status: "running", context: ctx });
        const successors = getSuccessors(workflow.definition, stuck.nodeId, "default");
        await walkDag(workflow.definition, stuck.runId, ctx, successors);
      } else {
        // Task failed or cancelled — mark run failed
        const reason = stuck.taskStatus === "failed" ? "Task failed" : "Task cancelled";
        updateWorkflowRunStep(stuck.stepId, {
          status: "failed",
          error: reason,
          finishedAt: new Date().toISOString(),
        });
        updateWorkflowRun(stuck.runId, {
          status: "failed",
          error: reason,
          finishedAt: new Date().toISOString(),
        });
      }
      recovered++;
    } catch (err) {
      console.error(`[workflows] Failed to recover stuck run ${stuck.runId}:`, err);
    }
  }
  return recovered;
}
```

