 1→import type { NodeResult } from "../engine";
 2→
 3→export interface PropertyMatchCondition {
 4→  field: string; // dot-path into context, e.g. "trigger.source"
 5→  op: "eq" | "neq" | "contains" | "not_contains" | "gt" | "lt" | "exists";
 6→  value?: unknown;
 7→}
 8→
 9→export interface PropertyMatchConfig {
10→  conditions: PropertyMatchCondition[];
11→  mode?: "all" | "any"; // default: "all"
12→}
13→
14→export function executePropertyMatch(
15→  config: PropertyMatchConfig,
16→  ctx: Record<string, unknown>,
17→): NodeResult {
18→  const mode = config.mode ?? "all";
19→  const results = config.conditions.map((cond) => evaluateCondition(cond, ctx));
20→  const passed = mode === "all" ? results.every(Boolean) : results.some(Boolean);
21→  return { mode: "instant", nextPort: passed ? "true" : "false", output: { passed, results } };
22→}
23→
24→function evaluateCondition(cond: PropertyMatchCondition, ctx: Record<string, unknown>): boolean {
25→  const value = resolvePath(ctx, cond.field);
26→  switch (cond.op) {
27→    case "eq":
28→      return value === cond.value;
29→    case "neq":
30→      return value !== cond.value;
31→    case "contains":
32→      return Array.isArray(value)
33→        ? value.includes(cond.value)
34→        : String(value ?? "").includes(String(cond.value));
35→    case "not_contains":
36→      return Array.isArray(value)
37→        ? !value.includes(cond.value)
38→        : !String(value ?? "").includes(String(cond.value));
39→    case "gt":
40→      return Number(value) > Number(cond.value);
41→    case "lt":
42→      return Number(value) < Number(cond.value);
43→    case "exists":
44→      return value != null;
45→    default:
